   211→bool check_head_dim_size_mem_efficient(sdp_params const& params, bool debug) {
   212→  const auto query_size_last = params.query.sym_size(-1);
   213→  const auto value_size_last = params.value.sym_size(-1);
   214→  const int64_t alignment = minimum_gemm_alignment(params);
   215→  if (!(query_size_last == params.key.sym_size(-1) &&
   216→        query_size_last % alignment == 0 && query_size_last > 0 &&
   217→        value_size_last % alignment == 0 && value_size_last > 0)) {
   218→    if (debug) {
   219→      TORCH_WARN(
   220→          "Mem efficient attention requires last dimension of inputs to be divisible by ",
   221→          alignment,
   222→          ". ",
   223→          "Got Query.size(-1): ",
   224→          query_size_last,
   225→          ", Key.size(-1): ",
   226→          params.key.sym_size(-1),
   227→          ", Value.size(-1): ",
   228→          params.value.sym_size(-1),
   229→          " instead.");
   230→    }
   231→    return false;
   232→  }
   233→  return true;
   234→}
