   262→bool check_flash_attention_hardware_support(sdp_params const& params, bool debug) {
   263→  // Check that the gpu is capable of running flash attention
   264→  using sm80 = SMVersion<8, 0>;
   265→  using sm121 = SMVersion<12, 1>;
   266→#if USE_ROCM
   267→#if USE_ROCM_ATTENTION
   268→  if(at::globalContext().getROCmFAPreferredBackend() == at::ROCmFABackend::Ck) {
   269→    // User explicitly set CK as the flash attention backend. Return true for now
   270→    // TODO: Flesh out sanity checks
   271→    return true;
   272→  } else {
   273→    auto stream = at::cuda::getCurrentCUDAStream().stream();
   274→    if (hipSuccess != aotriton::v2::flash::check_gpu(stream)) {
   275→        auto dprops = at::cuda::getCurrentDeviceProperties();
   276→        if (debug) {
   277→            TORCH_WARN(
   278→                    "Flash attention was not compiled for current AMD GPU architecture. Attempting to run on architecture ", dprops->gcnArchName);
   279→        }
   280→        return false;
   281→    }
   282→#if AOTRITON_VERSION_MINOR >= 9
   283→    if (aotriton::isArchExperimentallySupported(stream)) {
   284→      static const bool enable_experimental = c10::utils::check_env("TORCH_ROCM_AOTRITON_ENABLE_EXPERIMENTAL") == true;
   285→      if (!enable_experimental) {
   286→        TORCH_WARN_ONCE("Flash Efficient attention on Current AMD GPU is still experimental."
   287→            " Enable it with TORCH_ROCM_AOTRITON_ENABLE_EXPERIMENTAL=1.");
   288→        return false;
   289→      }
   290→    }
   291→#endif
   292→  }
   293→#else
   294→  return false;
   295→#endif
   296→#else
   297→  auto dprops = at::cuda::getCurrentDeviceProperties();
   298→  if (!check_sm_version<sm80, sm121>(dprops)) {
   299→    if (debug) {
   300→      TORCH_WARN(
   301→          "Flash attention only supports gpu architectures in the range [sm80, sm121]. Attempting to run on a sm ",
   302→          dprops->major,
   303→          ".",
   304→          dprops->minor,
   305→          " gpu.");
   306→    }
   307→    return false;
   308→  }
   309→#endif
   310→  return true;
   311→}
