   435→bool check_cudnn_tensor_shapes(sdp_params const& params, bool debug) {
   436→  const auto s_q = params.query.sym_size(2);
   437→  const auto s_k = params.key.sym_size(2);
   438→  const auto d_qk = params.query.sym_size(3);
   439→  const auto d_v = params.value.sym_size(3);
   440→  long cudnn_version = at::detail::getCUDAHooks().versionRuntimeCuDNN();
   441→  if (cudnn_version < 8903) {
   442→    if (debug) {
   443→      TORCH_WARN("SDPA fprop requires cudnn 8.9.3 or higher");
   444→    }
   445→    return false;
   446→  }
   447→  if (cudnn_version < 8906 && params.dropout != 0.0) {
   448→    if (debug) {
   449→      TORCH_WARN("Dropout reference is only supported on 8.9.6 onwards.");
   450→    }
   451→    return false;
   452→  }
   453→  auto head_dim_limit = 128;
   454→  if (cudnn_version >= 91000) {
   455→    auto dprops = at::cuda::getCurrentDeviceProperties();
   456→    if (dprops->major == 9 && !dprops->minor) {
   457→      head_dim_limit = 256;
   458→    }
   459→  }
   460→  if (d_qk > head_dim_limit || d_v > head_dim_limit) {
   461→    if (debug) {
   462→      TORCH_WARN("head_dim should be no more than ", head_dim_limit);
   463→    }
   464→    return false;
   465→  }
   466→  if (d_qk % 8 != 0 || d_v % 8 != 0) {
   467→    if (debug) {
   468→      TORCH_WARN("head_dim should be a multiple of 8");
   469→    }
   470→    return false;
   471→  }
   472→  if (cudnn_version < 8906 && s_k % 64 != 0 ) {
   473→    if (debug) {
   474→      TORCH_WARN("not-multiple-of-64 seq_kv is not supported below 8.9.6");
   475→    }
   476→    return false;
   477→  }
   478→  if (cudnn_version < 90000) {
   479→    if (s_q < 64) {
   480→      if (debug) {
   481→        TORCH_WARN("s_q less than 64 is not supported before cudnn 9.0.0");
   482→      }
   483→      return false;
   484→    }
   485→    if (params.dropout != 0.0 && (s_q % 64 != 0 || s_k % 64 != 0)) {
   486→      if (debug) {
   487→        TORCH_WARN(
   488→            "s_q not a multiple of 64 with padding/dropout is not supported with cudnn version 9.0.0");
   489→      }
   490→      return false;
   491→    }
   492→  }
   493→  if (s_k == 1) {
   494→    if (debug) {
   495→      TORCH_WARN_ONCE("cudnn SDPA does not support key/value sequence length 1.");
   496→    }
   497→    return false;
   498→  }
   499→  if (s_q == 1 && params.dropout != 0.0) {
   500→    if (debug) {
   501→      TORCH_WARN_ONCE("cudnn SDPA does not support query sequence length 1 with dropout.");
   502→    }
   503→    return false;
   504→  }
   505→  return true;
   506→}
   507→
   508→bool check_cudnn_layout(sdp_params const& params, bool debug) {
   509→  const int64_t h = params.query.size(1);
   510→  const int64_t s_q = params.query.size(2);
   511→  const int64_t d = params.query.size(3);
   512→  const int64_t s_k = params.key.size(2);
   513→  const int64_t s_v = params.value.size(2);
   514→  // corresponds to cuDNN's "packed QKV" layout
   515→  const bool packed_query_layout_ok = (params.query.stride(0) == s_q * 3 * h * d) &&
   516→                                 (params.query.stride(1) == d) &&
   517→                                 (params.query.stride(2) == 3 * h * d) &&
   518→                                 (params.query.stride(3) == 1);
